import React, { useState, useRef, useEffect, useCallback } from 'react';
import { createPortal } from 'react-dom';
import 'flag-icons/css/flag-icons.min.css';

/**
 * CustomSelect
 *
 * Supports:
 *  - searchable: shows a live-filter text input at the top of the dropdown
 *  - options[].countryCode: renders a CSS-based flag (flag-icons) instead of emoji
 */
const CustomSelect = ({
  name,
  value,
  onChange,
  options,
  disabled = false,
  placeholder = 'Select an option',
  className = '',
  style = {},
  required = false,
  error = null,
  hasIcon = false,
  showCheckmark = true,
  searchable = false,
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [dropdownPos, setDropdownPos] = useState({ top: 0, left: 0, width: 0 });
  const containerRef = useRef(null);
  const dropdownRef = useRef(null);
  const searchRef = useRef(null);

  const updatePosition = useCallback(() => {
    if (containerRef.current) {
      const rect = containerRef.current.getBoundingClientRect();
      setDropdownPos({
        top: rect.bottom + window.scrollY,
        left: rect.left + window.scrollX,
        width: rect.width,
      });
    }
  }, []);

  useEffect(() => {
    if (isOpen) {
      updatePosition();
      window.addEventListener('scroll', updatePosition, true);
      window.addEventListener('resize', updatePosition);
      // Auto-focus search input when opening
      if (searchable && searchRef.current) {
        setTimeout(() => searchRef.current?.focus(), 50);
      }
    } else {
      setSearchQuery('');
    }
    return () => {
      window.removeEventListener('scroll', updatePosition, true);
      window.removeEventListener('resize', updatePosition);
    };
  }, [isOpen, updatePosition, searchable]);

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event) => {
      const clickedOutsideContainer =
        containerRef.current && !containerRef.current.contains(event.target);
      const clickedOutsideDropdown =
        dropdownRef.current && !dropdownRef.current.contains(event.target);
      if (clickedOutsideContainer && clickedOutsideDropdown) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const selectedOption = options.find((opt) => opt.value === value);

  // Filter options based on search query — matches label, name, or dialCode
  const filteredOptions =
    searchable && searchQuery.trim()
      ? options.filter((opt) => {
          const q = searchQuery.toLowerCase();
          return (
            opt.label.toLowerCase().includes(q) ||
            (opt.name && opt.name.toLowerCase().includes(q))
          );
        })
      : options;

  const handleSelect = (optionValue) => {
    onChange({ target: { name, value: optionValue } });
    setIsOpen(false);
  };

  // Render a CSS-based flag using flag-icons (works on Windows/Android, unlike emoji)
  const renderFlag = (option, size = '1em') => {
    if (option && option.countryCode) {
      return (
        <span
          className={`fi fi-${option.countryCode.toLowerCase()}`}
          style={{
            fontSize: size,
            verticalAlign: 'middle',
            flexShrink: 0,
            lineHeight: 1,
            minWidth: size,
            minHeight: size,
            display: 'inline-block',
          }}
        />
      );
    }
    return null;
  };

  // Render what shows on the trigger button (show flag and code, flag smaller for mobile)
  const renderSelectedDisplay = () => {
    if (!selectedOption) {
      return (
        <span style={{ color: 'var(--text-muted)', fontSize: '0.95rem' }}>
          {placeholder}
        </span>
      );
    }
    return (
      <span
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: '6px',
          fontSize: '0.95rem',
          fontWeight: '500',
          minWidth: 0,
          overflow: 'hidden',
        }}
      >
        {renderFlag(selectedOption, '1em')}
        <span style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
          {selectedOption.label}
        </span>
      </span>
    );
  };

  const portalContent =
    isOpen && !disabled ? (
      <div
        ref={dropdownRef}
        className="custom-select-options"
        style={{
          position: 'absolute',
          top: `${dropdownPos.top + 4}px`,
          left: `${dropdownPos.left}px`,
          width: `${dropdownPos.width}px`,
          zIndex: 99999,
          maxHeight: '300px',
          display: 'flex',
          flexDirection: 'column',
          borderRadius: '4px',
          border: '2px solid var(--border-secondary)',
          boxShadow: '0 4px 12px rgba(0, 0, 0, 0.15)',
          backgroundColor: 'var(--bg-input)',
          overflow: 'hidden',
        }}
      >
        {/* Search input */}
        {searchable && (
          <div
            style={{
              padding: '8px',
              borderBottom: '1px solid var(--border-secondary)',
              flexShrink: 0,
            }}
          >
            <input
              ref={searchRef}
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search country..."
              style={{
                width: '100%',
                padding: '6px 10px',
                border: '1px solid var(--border-secondary)',
                borderRadius: '4px',
                backgroundColor: 'var(--card)',
                color: 'var(--text-primary)',
                fontSize: '0.9rem',
                outline: 'none',
                boxSizing: 'border-box',
              }}
              onClick={(e) => e.stopPropagation()}
            />
          </div>
        )}

        {/* Options list */}
        <div style={{ overflowY: 'auto', flex: 1 }}>
          {filteredOptions.length === 0 ? (
            <div
              style={{
                padding: '12px',
                color: 'var(--text-muted)',
                fontSize: '0.9rem',
                textAlign: 'center',
              }}
            >
              No results found
            </div>
          ) : (
            filteredOptions.map((option, index) => (
              <button
                key={`${option.value}-${index}`}
                type="button"
                onClick={() => handleSelect(option.value)}
                style={{
                  width: '100%',
                  padding: '10px 12px',
                  backgroundColor:
                    value === option.value ? 'var(--accent-bg, #e0e7ff)' : 'transparent',
                  color: 'var(--text-primary)',
                  border: 'none',
                  textAlign: 'left',
                  cursor: 'pointer',
                  fontSize: '0.95rem',
                  transition: 'background-color 0.15s ease',
                  borderBottom:
                    index === filteredOptions.length - 1
                      ? 'none'
                      : '1px solid var(--border-secondary)',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px',
                }}
                onMouseEnter={(e) => {
                  if (value !== option.value) {
                    e.currentTarget.style.backgroundColor = 'var(--bg-hover)';
                  }
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.backgroundColor =
                    value === option.value ? 'var(--accent-bg, #e0e7ff)' : 'transparent';
                }}
              >
                {renderFlag(option, '0.95em')}
                {showCheckmark && value === option.value && (
                  <span style={{ color: 'var(--accent)', fontWeight: 700, fontSize: '0.85rem' }}>
                    ✓
                  </span>
                )}
                {/* Show country name + dial code when name is available */}
                {option.name ? (
                  <span style={{ display: 'flex', alignItems: 'center', gap: '6px', minWidth: 0 }}>
                    <span style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', flex: 1 }}>
                      {option.name}
                    </span>
                    <span style={{ color: 'var(--text-muted)', fontSize: '0.85rem', flexShrink: 0 }}>
                      {option.label}
                    </span>
                  </span>
                ) : (
                  <span>{option.label}</span>
                )}
              </button>
            ))
          )}
        </div>
      </div>
    ) : null;

  return (
    <div
      ref={containerRef}
      style={{ position: 'relative', width: '100%', ...style }}
      className={className}
    >
      <button
        type="button"
        className={`custom-select-trigger ${hasIcon ? 'has-icon' : ''}`}
        onClick={() => !disabled && setIsOpen(!isOpen)}
        disabled={disabled}
      >
        {renderSelectedDisplay()}
        <span className={`custom-select-arrow ${isOpen ? 'open' : ''}`}>
          <i className="fa-solid fa-chevron-down" />
        </span>
      </button>

      {portalContent && document.body && createPortal(portalContent, document.body)}

      {error && (
        <p style={{ color: '#ef4444', fontSize: '12px', marginTop: '4px' }}>{error}</p>
      )}
    </div>
  );
};

export default CustomSelect;
